const ctx = $('Set: Account Context2').first().json;
const raw = ($json.value || '[]').toString();
let arr = [];
try {
  const parsed = JSON.parse(raw);
  if (Array.isArray(parsed)) arr = parsed.map(v => Number(v)).filter(v => Number.isFinite(v));
} catch { arr = []; }
const now = Math.floor(Date.now() / 1000);
const windowMinutes = 30;
const maxAttempts = 5;
const windowSeconds = Math.max(60, Math.floor(windowMinutes * 60));
const cutoff = now - windowSeconds;
const recent = arr.filter(ts => ts >= cutoff);
const canProceed = recent.length < maxAttempts;
const updated = canProceed ? [...recent, now] : [...recent];
let cooldownMinutes = 0;
if (!canProceed && recent.length > 0) {
  const oldest = Math.min(...recent);
  const waitSec = Math.max(0, windowSeconds - (now - oldest));
  cooldownMinutes = Math.ceil(waitSec / 60);
}
return {
  json: {
    ...ctx,
    attempts: recent.length,
    max_attempts: maxAttempts,
    window_minutes: windowMinutes,
    can_proceed: canProceed,
    cooldown_minutes: cooldownMinutes,
    rate_limit_timestamps: updated,
    rate_limit_json: JSON.stringify(updated),
  },
};

const c = $('Set: Account Context2').first().json;
const rate = $('Code: Parse Attempts2').first()?.json || {};
const queuePayload = {
  email: c.email,
  order_number: c.order_number,
  phone: c.phone,
  conversation_id: c.conversation_id,
  chatwoot_account_id: c.chatwoot_account_id,
};
return { json: { ...c, cooldown_minutes: Number(rate.cooldown_minutes || 0), queue_item: JSON.stringify(queuePayload) } };

