const input = $('Set: Normalize Inputs2').first().json;
const row = $json || {};
const rowEmail = (row.Email || row.email || row['Account Email'] || '').toString().trim().toLowerCase();
const rowOrder = (row['Order Number'] || row.OrderNumber || row.order_number || row.order || '').toString().trim();
const providerRaw = (row.provider_type || row.ProviderType || row.provider || row.Provider || row.Company || '').toString().trim().toLowerCase();
const provider = providerRaw.includes('mail') ? 'mailtm' : (providerRaw || 'gmail');
const password = (row.account_password || row.password || row.Pass || row.pass || '').toString().trim();
const is_known = rowEmail !== '' && rowEmail === input.email && (rowOrder === '' || rowOrder === input.order_number);
return { json: { ...input, sheet_row: row, row_email: rowEmail, row_order: rowOrder, provider, password, is_known } };

const SERVICE_MIN_PER_PERSON = 2;

// List Length node output is usually like: { "queue:cuz...": 1 }
const len = Number(Object.values($json)[0] ?? 0) || 0;

// Base ahead = waiting people before you in the list
const baseAhead = Math.max(0, len - 1);

// Check if account is currently locked (someone is being processed)
let hasLock = false;
try {
  const lockJson = $('Redis GET: account_lock2').first().json; // your existing node name
  const lockVal = Object.values(lockJson)[0];
  hasLock = lockVal !== undefined && lockVal !== null && String(lockVal).trim() !== '';
} catch (e) {
  hasLock = false; // node not executed in this path
}

// If locked, add 1 person (the one currently being served)
const ahead = baseAhead + (hasLock ? 1 : 0);
const etaMinutes = ahead * SERVICE_MIN_PER_PERSON;

return {
  json: {
    queue_len: len,
    ahead_count: ahead,
    eta_minutes: etaMinutes,
    service_minutes_per_person: SERVICE_MIN_PER_PERSON,
    has_lock: hasLock,
  }
};

